valueExpression.expression:
{%- comment -%} === SECTION 1: HEADER === {%- endcomment -%}
{%- assign root = QuestionnaireResponse | fhirpath: "item.where(linkId='019c4706-3d88-799c-8767-fed5898075e1')" | first -%}
{%- assign test_type_group = root | fhirpath: "item.where(linkId='019d3db2-e0c4-7fff-854c-95b40a1d03e7')" | first -%}
{%- assign ligfiets = test_type_group | fhirpath: "item.where(linkId='019d3dae-17e0-7fff-84fb-868b50067657').answer[0].valueCoding.display" | first -%}
{%- assign regadenoson = test_type_group | fhirpath: "item.where(linkId='019cae08-1c3a-7aa7-99b8-b65a55f18c29').answer[0].valueCoding.display" | first -%}
{%- assign spiro = test_type_group | fhirpath: "item.where(linkId='019d6870-0942-7666-abed-f626d68a5490').answer[0].valueCoding.display" | first -%}

{%- if regadenoson == "ja" -%}
<div>Regadenoson stresstest. Dit is géén fietsproef.</div>
{%- else -%}
<div>Inspanningstest op {%- if ligfiets == "ja" %} een ligfiets{%- else %} fiets{%- endif -%}{%- if spiro == "ja" %} met spiroergometrie{%- endif -%}.</div>
{%- endif -%}

{%- comment -%} === SECTION 2: PROTOCOL === {%- endcomment -%}
{%- assign protocol_group = root | fhirpath: "item.where(linkId='019cadf7-0fe6-7aa7-97ae-bfb0dff20e15')" | first -%}
{%- assign soort_protocol = protocol_group | fhirpath: "item.where(linkId='019cae04-716c-7aa7-9964-e193ddec2553').answer[0].valueCoding.display" | first -%}
{%- assign start_wattage = protocol_group | fhirpath: "item.where(linkId='019c4706-3fe6-799c-8768-c3b0a8a4738c').answer[0].valueDecimal" | first -%}
{%- assign stijging = protocol_group | fhirpath: "item.where(linkId='019c470a-ab62-799c-87be-08a3df69201b').answer[0].valueDecimal" | first -%}
{%- assign per_min = protocol_group | fhirpath: "item.where(linkId='019c4711-bd82-799c-87e1-a44056478612').answer[0].valueDecimal" | first -%}

<div>Start aan {{ start_wattage | default: "XXX" }}W met een
{%- if soort_protocol -%}
  {%- if soort_protocol == "stapsgewijze belasting" %} stapsgewijze
  {%- elsif soort_protocol == "ramp protocol" %} geleidelijke
  {%- endif -%}
{%- else %} XXX
{%- endif %} stijging van {{ stijging | default: "XXX" }} W per {{ per_min | default: "XXX" }} minuten.</div>

{%- comment -%} === SECTION 3: INSPANNING === {%- endcomment -%}
{%- assign inspanning_group = root | fhirpath: "item.where(linkId='019d1f04-a852-7330-8782-9df409bbe060')" | first -%}
{%- assign duur = inspanning_group | fhirpath: "item.where(linkId='019c4722-e62a-799c-89e3-2c97936302a0').answer[0].valueDecimal" | first -%}
{%- assign seconden = inspanning_group | fhirpath: "item.where(linkId='019d2e97-3144-7bbf-aee2-c6efd27ea4e9').answer[0].valueDecimal" | first -%}
{%- assign piekbelasting = inspanning_group | fhirpath: "item.where(linkId='019c4722-fbce-799c-89ea-66b34dcaa3ac').answer[0].valueDecimal" | first -%}
{%- assign reden_stoppen = inspanning_group | fhirpath: "item.where(linkId='019c47f8-7000-799c-91c6-78452dea92e8').answer.valueCoding.display" -%}

<div>Inspanning van {{ duur | default: "XXX" }} minuten
{%- if seconden %} (en {{ seconden }} seconden){%- endif %} met een piekbelasting van {{ piekbelasting | default: "XXX" }} W.</div>

{%- if reden_stoppen.size > 0 -%}
<div>Reden voor stoppen van de test: {{ reden_stoppen | join: ", " }}.</div>
{%- else -%}
<div>Reden voor stoppen van de test: XXX.</div>
{%- endif -%}

{%- comment -%} === SECTION 4: BLOEDDRUK & HARTSLAG === {%- endcomment -%}
{%- assign bloeddruk_group = root | fhirpath: "item.where(linkId='019cae00-ccb5-7aa7-98d8-d36646c999be')" | first -%}
{%- assign max_syst = bloeddruk_group | fhirpath: "item.where(linkId='019c4781-6e9b-799c-8b9b-34802222313f').answer[0].valueDecimal" | first -%}
{%- assign max_diast = bloeddruk_group | fhirpath: "item.where(linkId='019c4783-92fe-799c-8bf0-bb4495251181').answer[0].valueDecimal" | first -%}

{%- assign hartslag_group = root | fhirpath: "item.where(linkId='019db547-c962-7009-8baf-e510f6db2569')" | first -%}
{%- assign max_hartslag = hartslag_group | fhirpath: "item.where(linkId='019db547-cba8-7009-8bb0-07b539cf1857').answer[0].valueDecimal" | first -%}
{%- assign pct_max_hartslag = hartslag_group | fhirpath: "item.where(linkId='019db547-cba8-7009-8bb0-156a90a26a89').answer[0].valueDecimal" | first -%}

{%- assign interpretatie_hartslag = hartslag_group | fhirpath: "item.where(linkId='019c6b40-3452-777a-be3a-dd349ad2c387').answer[0].valueCoding.display" | first -%}

{%- if interpretatie_hartslag == "onder betablokkade" -%}
  {%- assign interpretatie_tekst = "onder betablokkade" -%}
{%- elsif interpretatie_hartslag == "onvoldoende betablokkade" -%}
  {%- assign interpretatie_tekst = "Wijzend op onvoldoende betablokkade" -%}
{%- elsif interpretatie_hartslag == "onvolledige betablokkade" -%}
  {%- assign interpretatie_tekst = "Wijzend op onvolledige betablokkade" -%}
{%- elsif interpretatie_hartslag == "goede betablokkade" -%}
  {%- assign interpretatie_tekst = "Wijzend op goede betablokkade" -%}
{%- elsif interpretatie_hartslag == "te sterke betablokkade" -%}
  {%- assign interpretatie_tekst = "Wijzend op te sterke betablokkade" -%}
{%- elsif interpretatie_hartslag == "onder bradycardiserende calciumantagonist" -%}
  {%- assign interpretatie_tekst = "Onder bradycardiserende calciumantagonist" -%}
{%- endif -%}

<div>Maximale bloeddruk: {{ max_syst | default: "XXX" }}/{{ max_diast | default: "XXX" }} mmHg en maximale hartslag: {{ max_hartslag | default: "XXX" }}/min ({{ pct_max_hartslag | default: "XXX" }}% van verwachte maximum){%- if interpretatie_tekst %}, {{ interpretatie_tekst }}{%- endif %}.</div>

{%- comment -%} === SECTION 5: REPOLARISATIE === {%- endcomment -%}
{%- assign repolarisatie_item = root | fhirpath: "item.where(linkId='019c4793-d723-799c-8c94-cd1b531f9db7')" | first -%}
{%- assign repolarisatie = repolarisatie_item | fhirpath: "answer[0].valueCoding.display" | first -%}

{%- if repolarisatie == "geen wijzigingen" or repolarisatie == "Geen wijzigingen" -%}
<div>Repolarisatie: geen significante wijzigingen.</div>

{%- elsif repolarisatie == "J punt daling" -%}
<div>Repolarisatie: J punt daling.</div>

{%- elsif repolarisatie == "ST wijziging" -%}
{%- assign st_group = repolarisatie_item | fhirpath: "answer[0].item.where(linkId='019d1f6c-3076-722f-aa97-873d56c4a093')" | first -%}
{%- assign st_type = st_group | fhirpath: "item.where(linkId='019c47a7-9ae4-799c-8d54-c67b61699b73').answer[0].valueCoding.display" | first -%}
{%- assign st_mm = st_group | fhirpath: "item.where(linkId='019c47ac-8b40-799c-8d81-c6b0c5d27d87').answer[0].valueDecimal" | first -%}
{%- assign st_slope = st_group | fhirpath: "item.where(linkId='019c6b54-0b22-777a-be95-745085be605a').answer[0].valueCoding.display" | first -%}
{%- assign st_afleidingen = st_group | fhirpath: "item.where(linkId='019c47ae-0724-799c-8d96-534c9cf7391f').answer.valueCoding.display" -%}
{%- assign st_interpretatie = st_group | fhirpath: "item.where(linkId='019c8ef4-5c19-799c-a485-bd9b43e4137d').answer[0].valueCoding.display" | first -%}

{%- if st_type or st_mm or st_slope or st_afleidingen.size > 0 or st_interpretatie -%}
<div>Repolarisatie: {{ st_interpretatie | default: "XXX" }} {{ st_type | default: "XXX" }} van {{ st_mm | default: "XXX" }}mm ({{ st_slope | default: "XXX" }} segment) in afleidingen: {{ st_afleidingen | join: ", " | default: "XXX" }}.</div>
{%- else -%}
<div>Repolarisatie: ST wijziging.</div>
{%- endif -%}

{%- elsif repolarisatie == "niet te beoordelen" -%}
{%- assign niet_beoordeel_reden = repolarisatie_item | fhirpath: "answer[0].item.where(linkId='019c479b-b403-799c-8ce4-9701188c1cc8').answer[0].valueCoding.display" | first -%}

{%- if niet_beoordeel_reden == "Pacemaker" -%}
  {%- assign niet_beoordeel_tekst = "aanwezigheid van een pacemaker" -%}
{%- elsif niet_beoordeel_reden == "ICD (defibrillator)" -%}
  {%- assign niet_beoordeel_tekst = "aanwezigheid van een defibrillator" -%}
{%- elsif niet_beoordeel_reden == "volledig linker bundeltakblok" -%}
  {%- assign niet_beoordeel_tekst = "volledig linker bundeltakblok" -%}
{%- elsif niet_beoordeel_reden == "Inspanningsgebonden linker bundeltakblok" -%}
  {%- assign niet_beoordeel_tekst = "inspanningsgebonden linker bundeltakblok" -%}
{%- elsif niet_beoordeel_reden == "Digitalis impregnatie" -%}
  {%- assign niet_beoordeel_tekst = "digitalis impregnatie" -%}
{%- elsif niet_beoordeel_reden == "Wolff-Parkinson-White" -%}
  {%- assign niet_beoordeel_tekst = "Wolff-Parkinson White syndroom" -%}
{%- else -%}
  {%- assign niet_beoordeel_tekst = "XXX" -%}
{%- endif -%}

<div>Repolarisatie: niet te beoordelen door {{ niet_beoordeel_tekst }}.</div>

{%- else -%}
<div>Repolarisatie: XXX.</div>
{%- endif -%}

{%- comment -%} === SECTION 6: RITMESTOORNISSEN === {%- endcomment -%}
{%- assign ritme_group = root | fhirpath: "item.where(linkId='019d1efe-6153-7330-86ec-e8360dcc5883')" | first -%}
{%- assign ritmestoornissen = ritme_group | fhirpath: "item.where(linkId='019c47c6-92ae-799c-900c-0a0c2a9fbbf0').answer.valueCoding.display" -%}
{%- assign ventr_extrasystolen_raw = ritme_group | fhirpath: "item.where(linkId='019c47d4-d820-799c-90ab-40eefcca48dc').answer.valueCoding.display" -%}
{%- assign av_blok_raw = ritme_group | fhirpath: "item.where(linkId='019cd74e-0653-7000-82fa-853daf5dd419').answer.valueCoding.display" -%}

{%- comment -%} Map ventriculaire extrasystolen options to short form {%- endcomment -%}
{%- assign ventr_mapped = "" -%}
{%- for v in ventr_extrasystolen_raw -%}
  {%- if v == "zeldzame ventriculaire extrasystolen" -%}{%- assign ventr_mapped = ventr_mapped | append: "zeldzaam," -%}
  {%- elsif v == "frequente ventriculaire extrasystolen" -%}{%- assign ventr_mapped = ventr_mapped | append: "frequent," -%}
  {%- elsif v == "unifocaal ventriculaire extrasystolen" -%}{%- assign ventr_mapped = ventr_mapped | append: "unifocaal," -%}
  {%- elsif v == "multifocale ventriculaire extrasystolen" -%}{%- assign ventr_mapped = ventr_mapped | append: "multifocaal," -%}
  {%- elsif v == "couplet ventriculair" -%}{%- assign ventr_mapped = ventr_mapped | append: "ventriculair couplet," -%}
  {%- elsif v == "triplet ventriculair" -%}{%- assign ventr_mapped = ventr_mapped | append: "ventriculair triplet," -%}
  {%- elsif v == "nemen af bij inspanning" -%}{%- assign ventr_mapped = ventr_mapped | append: "afnemend bij inspanning," -%}
  {%- elsif v == "nemen toe bij inspanning" -%}{%- assign ventr_mapped = ventr_mapped | append: "toenemend bij inspanning," -%}
  {%- endif -%}
{%- endfor -%}
{%- assign ventr_mapped = ventr_mapped | remove_last: "," | split: "," -%}

{%- comment -%} Map AV-blok options to short form {%- endcomment -%}
{%- assign av_mapped = "" -%}
{%- for a in av_blok_raw -%}
  {%- if a == "eerstegraads atrioventriculair blok" -%}{%- assign av_mapped = av_mapped | append: "eerstegraads," -%}
  {%- elsif a == "tweedegraads atrioventriculair blok (Mobitz type 1)" -%}{%- assign av_mapped = av_mapped | append: "tweedegraads Mobitz type 1," -%}
  {%- elsif a == "tweedegraads atrioventriculair blok (Mobitz type 2)" -%}{%- assign av_mapped = av_mapped | append: "tweedegraads Mobitz type 2," -%}
  {%- elsif a == "derdegraads atrioventriculair blok" -%}{%- assign av_mapped = av_mapped | append: "derdegraads," -%}
  {%- elsif a == "verdwijnt bij inspanning" -%}{%- assign av_mapped = av_mapped | append: "verdwijnt bij inspanning," -%}
  {%- elsif a == "treedt op bij inspanning" -%}{%- assign av_mapped = av_mapped | append: "treedt op bij inspanning," -%}
  {%- endif -%}
{%- endfor -%}
{%- assign av_mapped = av_mapped | remove_last: "," | split: "," -%}

{%- if ritmestoornissen.size > 0 -%}
  {%- if ritmestoornissen.first == "geen" -%}
<div>Ritmestoornissen: geen.</div>
  {%- else -%}
<div>Ritmestoornissen: {% for r in ritmestoornissen -%}{%- if forloop.first == false %}, {% endif -%}{{- r -}}
{%- if r == "ventriculaire extrasystolen" -%}{%- if ventr_mapped.size > 0 and ventr_mapped.first != "" %} ({{ ventr_mapped | join: ", " }}){%- endif -%}{%- endif -%}
{%- if r == "AV-blok" -%}{%- if av_mapped.size > 0 and av_mapped.first != "" %} ({{ av_mapped | join: ", " }}){%- endif -%}{%- endif -%}
{%- endfor -%}.</div>
  {%- endif -%}
{%- else -%}
<div>Ritmestoornissen: XXX.</div>
{%- endif -%}

{%- comment -%} === SECTION 7: BESLUIT === {%- endcomment -%}
{%- assign besluit = root | fhirpath: "item.where(linkId='019daeed-d5cf-7aa5-ae7a-55f29782be60').answer[0].valueString" | first -%}
{%- assign besluit1 = root | fhirpath: "item.where(linkId='019d1f10-2e2e-7330-8882-58c6448c0c49').answer[0].valueString" | first -%}
{%- assign besluit2 = root | fhirpath: "item.where(linkId='019d1f16-b3f6-7330-88b7-a854e5117462').answer[0].valueString" | first -%}
<br/>
{%- if besluit1 -%}
<div>{{ besluit1 }}</div>
{%- elsif besluit2 -%}
<div>{{ besluit2 }}</div>
{%- elsif besluit -%}
<div>{{ besluit }}</div>
{%- endif -%}
